def lcs_len(a, b):
    # dynamic programming. But lengths may be long; but here short. We'll implement O(n*m)
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            tmp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                if dp[j] < dp[j-1]:
                    dp[j] = dp[j-1]
            prev = tmp
    return dp[m]

def sim_ratio(a, b):
    # normalized LCS ratio: 2*lcs/(len(a)+len(b)).
    if not a and not b:
        return 1.0
    l = lcs_len(a, b)
    return 2*l/(len(a)+len(b))

